// 导出题库（用于 HTML 中引用）
if (typeof module !== 'undefined' && module.exports) {
    module.exports = ArticleDatabase;
}

// 辅助函数：获取指定语种的随机文章
function getRandomArticle(languageKey) {
    const languageData = ArticleDatabase[languageKey];
    if (!languageData || !languageData.articles || languageData.articles.length === 0) {
        return null;
    }
    const randomIndex = Math.floor(Math.random() * languageData.articles.length);
    return languageData.articles[randomIndex];
}

// 辅助函数：获取所有语种列表（按类型分组）
function getLanguagesByType(type) {
    const languages = [];
    for (const [key, value] of Object.entries(ArticleDatabase)) {
        if (value.type === type) {
            languages.push({
                key: key,
                name: value.name,
                type: value.type
            });
        }
    }
    return languages;
}

// 辅助函数：获取所有语种（用于下拉菜单）
function getAllLanguages() {
    const languages = [];
    for (const [key, value] of Object.entries(ArticleDatabase)) {
        languages.push({
            key: key,
            name: value.name,
            type: value.type
        });
    }
    return languages;
}